class Solution {
    public int binaryGap(int n) {
        int maxGap = 0;
        int prev = -1;
        int currentPos = 0;
        while (n > 0) {
            int bit = n & 1;
            if (bit == 1) {
                if (prev != -1) {
                    int gap = currentPos - prev;
                    if (gap > maxGap) {
                        maxGap = gap;
                    }
                }
                prev = currentPos;
            }
            n = n >> 1;
            currentPos++;
        }
        return maxGap;
    }
}

